#include<cstdio>
#include<algorithm>
#include<cstring>
#include<iostream>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define int long long
inline int Max(int x,int y){return x>y?x:y;}
inline int Min(int x,int y){return x<y?x:y;}
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,M=2e5+10,INF=0x3f3f3f3f;
int n,Lmx,Wmx,dis[N],dep[N];bool vis[N];long long ans,res;
struct Graph
{
	int head[N],des[M],nxt[M],val[M],cnt;
	inline void ins(int x,int y,int z){nxt[++cnt]=head[x];head[x]=cnt;des[cnt]=y;val[cnt]=z;}
	inline void Init(bool q=0){memset(head,0,sizeof(head));cnt=q;}
}a;
struct Sort
{
	int dis,dep;inline Sort(int x=0,int y=0){dis=x;dep=y;}
	inline bool operator<(const Sort x){return dis^x.dis?dis<x.dis:dep<x.dep;}
}Q[N];
struct BITree
{
	int t[N],n;inline void Init(int nn=N-10){memset(t,0,sizeof(t));n=nn;}
	inline void add(int pos,int val){while(pos<=n)t[pos]+=val,pos+=(pos&-pos);return;}
	inline int qry(int pos){int res=0;while(pos)res+=t[pos],pos^=(pos&-pos);return res;}
}t;
int cbt,cnt,cqt,ql[N],qr[N];
inline void dfs(int u,int Dis,int Dep=1,int fa=0)
{
	if(Dis>Wmx||Dep>Lmx)return;ans+=2;
//	printf("%d %d %d\n",u,Dis,Dep);
	dis[++cnt]=Dis;dep[cnt]=Dep;grep(a,u,i)
	{
		int v=a.des[i];if(vis[v]||v==fa)continue;
		dfs(v,Dis+a.val[i],Dep+1,u);
	}
}
inline int Cnt(int l,int r)
{
	res=0;cqt=0;rep(l,r,i){Sort tmp(dis[i],dep[i]);Q[++cqt]=tmp;}
	std::sort(Q+1,Q+cqt+1);rep(1,cqt,i)t.add(Q[i].dep,1);int cur=cqt;
	rep(1,cqt,i)
	{
		while(cur&&Q[cur].dis+Q[i].dis>Wmx)t.add(Q[cur--].dep,-1);
		res+=t.qry(Lmx-Q[i].dep);res-=(Q[i].dep+Q[i].dep<=Lmx&&Q[i].dis+Q[i].dis<=Wmx);
	}while(cur)t.add(Q[cur--].dep,-1);
//	rep(1,cqt,i)printf("%d %d\n",Q[i].dis,Q[i].dep);
//	printf("res : %d\n",res);
	return res;
}
inline void Solve(int u)
{
	cbt=0;cnt=0;grep(a,u,i)
	{
		int v=a.des[i];if(vis[v])continue;
		int lst=cnt+1;dfs(v,a.val[i]);
		ans-=Cnt(lst,cnt);
	}
	ans+=Cnt(1,cnt);
//	rep(1,cnt,i)printf("%d ",dep[i]);puts("");
//	rep(1,cnt,i)printf("%d ",dis[i]);puts("");
//	printf("%lld\n",ans);
}
int mn,rt,tsz,siz[N];inline void GetRt(int u,int fa=0)
{
	!fa?(mn=n,tsz=siz[u]):0;int son=0;siz[u]=1;
	grep(a,u,i)
	{
		int v=a.des[i];if(v==fa||vis[v])continue;
		GetRt(v,u);siz[u]+=siz[v];son=Max(son,siz[v]);
	}	
	son=Max(son,tsz-son);son<mn?(mn=son,rt=u):0;
}
inline void Slide(int u)
{
	vis[u]=1;Solve(u);grep(a,u,i)
	{
		int v=a.des[i];if(vis[v])continue;
		GetRt(v);Slide(rt);
	}
}
signed main()
{
	n=read();Lmx=read();Wmx=read();a.Init();t.Init();
	rep(2,n,x){int y=read(),z=read();a.ins(x,y,z);a.ins(y,x,z);}
	siz[1]=n;GetRt(1);Slide(rt);std::cout<<(ans>>1ll)<<'\n';return 0;
}
